t.script:
                //
(function(){
    'use strict';
    var INTERVAL=15000;
    var A=[{key:'open_tickets',sel:'[data-key="open_tickets"] .stat-value'},{key:'total_tickets',sel:'[data-key="total_tickets"] .stat-value'},{key:'high_priority',sel:'[data-key="high_priority"] .stat-value'},{key:'urgent',sel:'[data-key="urgent"] .stat-value'},{key:'avg_open_hours',sel:'[data-key="avg_open_hours"] .stat-value'},{key:'total_hours',sel:'[data-key="total_hours"] .stat-value'},{key:'avg_high_hours',sel:'[data-key="avg_high_hours"] .stat-value'},{key:'avg_urgent_hours',sel:'[data-key="avg_urgent_hours"] .stat-value'},{key:'resolved_tickets',sel:'[data-key="resolved_tickets"] .stat-value'},{key:'solve_rate',sel:'[data-key="solve_rate"] .stat-value',sfx:'%'},{key:'high_resolved',sel:'[data-key="high_resolved"] .stat-value'},{key:'urgent_resolved',sel:'[data-key="urgent_resolved"] .stat-value'}];
    var P=[{key:'today_closed',sel:'[data-key="today_closed"] .performance-value'},{key:'avg_resolve_rate',sel:'[data-key="avg_resolve_rate"] .performance-value',sfx:'%'},{key:'daily_target',sel:'[data-key="daily_target"] .performance-value',sfx:'%'},{key:'achievement',sel:'[data-key="achievement"] .performance-value',sfx:'%'},{key:'sample_performance',sel:'[data-key="sample_performance"] .score-badge',sfx:'%'}];
    function upd(sel,val,sfx){var el=document.querySelector(sel);if(el)el.textContent=val+(sfx||'');}
    function flash(sel){var el=document.querySelector(sel);if(el){el.style.transition='color 0.3s';el.style.color='#1e88c7';setTimeout(function(){el.style.color='';},600);}}
    function updBar(v){var b=document.querySelector('.progress-bar');if(b){b.style.width=v+'%';b.className='progress-bar '+(v>=80?'bg-success':'bg-warning');}}
    function updBarLabel(v){var ls=document.querySelectorAll('.progress-label span');if(ls.length>=2)ls[1].textContent=v+'%';}
    function updTime(){var now=new Date();var t=now.toLocaleTimeString([],{hour:'2-digit',minute:'2-digit'});document.querySelectorAll('.last-updated').forEach(function(el){el.innerHTML='<i class="bi bi-clock me-1"></i>Updated at '+t;});}
    function run(){
        fetch('/customer_support/dashboard/analytics',{method:'GET',credentials:'same-origin',headers:{'Accept':'application/json'}})
        .then(function(r){if(!r.ok)throw new Error(r.status);return r.json();})
        .then(function(d){
            var a=d.analytics||{},p=d.performance||{};
            A.forEach(function(i){var v=a[i.key];if(v!==undefined){upd(i.sel,v,i.sfx||'');flash(i.sel);}});
            P.forEach(function(i){var v=p[i.key];if(v!==undefined)upd(i.sel,v,i.sfx||'');});
            if(p.achievement!==undefined){updBar(p.achievement);updBarLabel(p.achievement);}
            updTime();
        }).catch(function(e){console.warn('Analytics refresh failed:',e);});
    }
    document.addEventListener('DOMContentLoaded',function(){run();setInterval(run,INTERVAL);});
})();
//

                //
document.addEventListener('DOMContentLoaded', function () {

    // Auto-hide alerts
    setTimeout(function () {
        document.querySelectorAll('.alert').forEach(function (a) { new bootstrap.Alert(a).close(); });
    }, 5000);

    // ── Column counts ─────────────────────────────────────────────────────
    function updatePortalCounts() {
        ['new','in_progress','resolved','closed'].forEach(function(state) {
            var col     = document.getElementById('portal-col-' + state);
            var countEl = document.getElementById('portal-count-' + state);
            if (col && countEl) countEl.textContent = col.querySelectorAll('.kanban-card').length;
        });
    }
    updatePortalCounts();

    // ── Page switching ────────────────────────────────────────────────────
    function hideAllPages() {
        document.getElementById('portal-overview-page').style.display  = 'none';
        document.getElementById('portal-kanban-page').style.display    = 'none';
        document.getElementById('portal-reporting-page').style.display = 'none';
    }
    function setActiveNav(id) {
        document.querySelectorAll('.header-nav .nav-link').forEach(function(l){ l.classList.remove('active'); });
        var el = document.getElementById(id);
        if (el) el.classList.add('active');
    }
    function showOverview() {
        hideAllPages();
        document.getElementById('portal-overview-page').style.display = 'block';
        setActiveNav('portalOverviewNav');
    }
    function showKanban() {
        hideAllPages();
        document.getElementById('portal-kanban-page').style.display = 'block';
        setActiveNav('portalTicketsNav');
        updatePortalCounts();
    }
    function showReporting() {
        hideAllPages();
        document.getElementById('portal-reporting-page').style.display = 'block';
        setActiveNav('portalReportingNav');
        loadReportData(currentDays);
    }

    document.getElementById('portalKanbanBtn').addEventListener('click', function () {
        showKanban();
        this.classList.add('active');
    });

    var ticketsNav = document.getElementById('portalTicketsNav');
    if (ticketsNav) {
        ticketsNav.addEventListener('click', function(e) { e.preventDefault(); showKanban(); });
    }

    var reportingNav = document.getElementById('portalReportingNav');
    if (reportingNav) {
        reportingNav.addEventListener('click', function(e) { e.preventDefault(); showReporting(); });
    }

    var reportActionCard = document.getElementById('portalReportActionCard');
    if (reportActionCard) {
        reportActionCard.addEventListener('click', function(e) { e.preventDefault(); showReporting(); });
    }

    document.getElementById('portalListBtn').addEventListener('click', function () {
        window.location.href = '/customer_support/tickets';
    });
    document.getElementById('portalKanbanActiveBtn').addEventListener('click', showKanban);

    // ── Card click ────────────────────────────────────────────────────────
    document.querySelectorAll('#portal-kanban-page .kanban-card').forEach(function (card) {
        card.addEventListener('click', function () {
            var id = this.getAttribute('data-ticket-id');
            if (id) window.location.href = '/customer_support/ticket/' + id;
        });
    });

    // ── Action cards ──────────────────────────────────────────────────────
    document.querySelectorAll('.action-card').forEach(function (card) {
        card.addEventListener('click', function (e) {
            if (!this.href || this.href === '#' || this.href.endsWith('#')) {
                e.preventDefault();
                this.style.transform = 'scale(0.95)';
                setTimeout(function() { card.style.transform = 'scale(1)'; }, 150);
            }
        });
    });

    // ── NOTIFICATION BELL ─────────────────────────────────────────────────
    var bell     = document.getElementById('portalNotifBell');
    var dropdown = document.getElementById('portalNotifDropdown');
    var badge    = document.getElementById('portalNotifBadge');
    var list     = document.getElementById('portalNotifList');

    bell.addEventListener('click', function (e) {
        e.stopPropagation();
        dropdown.classList.toggle('open');
    });
    document.addEventListener('click', function () { dropdown.classList.remove('open'); });
    dropdown.addEventListener('click', function (e) { e.stopPropagation(); });

    document.getElementById('portalMarkRead').addEventListener('click', function () {
        fetch('/customer_support/customer/notifications/mark_read', {
            method: 'POST', credentials: 'same-origin',
            headers: { 'Accept': 'application/json' }
        })
        .then(function () {
            badge.classList.add('d-none');
            badge.textContent = '0';
            list.innerHTML = '<div class="notif-empty">'
                + '<i class="bi bi-check-circle-fill" style="font-size:2rem;color:#22c55e;display:block;margin-bottom:.5rem;"></i>'
                + 'All caught up!</div>';
        });
    });

    document.getElementById('portalNotifViewTickets').addEventListener('click', function (e) {
        e.preventDefault();
        dropdown.classList.remove('open');
        showKanban();
    });

    function renderNotifications(items) {
        if (!items.length) {
            list.innerHTML = '<div class="notif-empty">'
                + '<i class="bi bi-check-circle-fill" style="font-size:2rem;color:#22c55e;display:block;margin-bottom:.5rem;"></i>'
                + 'No new notifications</div>';
            badge.classList.add('d-none');
            return;
        }
        badge.textContent = items.length;
        badge.classList.remove('d-none');
        list.innerHTML = items.map(function (n) {
            var href = n.ticket_id ? '/customer_support/ticket/' + n.ticket_id : '#';
            return '<a class="notif-item" href="' + href + '">'
                + '<div class="notif-icon-wrap ' + (n.cls || 'status') + '">'
                + '<i class="bi ' + (n.icon || 'bi-bell-fill') + '"></i></div>'
                + '<div class="notif-body">'
                + '<div class="notif-title">' + (n.message || '') + '</div>'
                + '<div class="notif-time">' + (n.time || '') + '</div>'
                + '</div>'
                + '<div class="notif-dot ' + (n.cls || 'status') + '"></div>'
                + '</a>';
        }).join('');
    }

    function loadNotifications() {
        fetch('/customer_support/customer/notifications', {
            method: 'GET', credentials: 'same-origin',
            headers: { 'Accept': 'application/json' }
        })
        .then(function (r) { return r.json(); })
        .then(function (data) { renderNotifications(data.notifications || []); })
        .catch(function () { renderNotifications([]); });
    }

    loadNotifications();
    setInterval(loadNotifications, 30000);

    // ═══════════════════════════════════════════════════════════════════════
    // ── REPORTING ──────────────────────────────────────────────────────────
    // ═══════════════════════════════════════════════════════════════════════

    var currentDays = 30;
    var chartInstances = {};

    // Day filter buttons
    document.querySelectorAll('#reportDayFilter .day-btn').forEach(function(btn) {
        btn.addEventListener('click', function() {
            document.querySelectorAll('#reportDayFilter .day-btn').forEach(function(b){ b.classList.remove('active'); });
            this.classList.add('active');
            currentDays = parseInt(this.getAttribute('data-days'), 10);
            loadReportData(currentDays);
        });
    });

    function destroyChart(id) {
        if (chartInstances[id]) {
            chartInstances[id].destroy();
            delete chartInstances[id];
        }
    }

    function loadReportData(days) {
        document.getElementById('reportLoading').style.display = 'flex';
        document.getElementById('reportContent').style.display = 'none';

        fetch('/customer_support/customer/reporting?days=' + days, {
            method: 'GET', credentials: 'same-origin',
            headers: { 'Accept': 'application/json' }
        })
        .then(function(r) { return r.json(); })
        .then(function(data) {
            if (!data.success) throw new Error('API error');
            renderReport(data);
            document.getElementById('reportLoading').style.display = 'none';
            document.getElementById('reportContent').style.display = 'block';
            // Set print subtitle
            var pd = document.getElementById('reportPrintDate');
            if (pd) pd.textContent = new Date().toLocaleDateString() + ' (Last ' + days + ' days)';
        })
        .catch(function(e) {
            console.error('Reporting fetch failed:', e);
            document.getElementById('reportLoading').innerHTML =
                '<i class="bi bi-exclamation-triangle" style="color:#ef4444;font-size:1.5rem;"></i>'
                + '<span style="color:#ef4444;">Could not load report data.</span>';
        });
    }

    function renderReport(data) {
        var kpis = data.kpis || {};

        // KPI cards
        document.getElementById('rKpiTotal').textContent    = kpis.total || 0;
        document.getElementById('rKpiResolved').textContent = kpis.resolved || 0;
        document.getElementById('rKpiOpen').textContent     = kpis.open || 0;
        document.getElementById('rKpiAvgHours').textContent = kpis.avg_resolution_hours || 0;
        var rateEl = document.getElementById('rKpiRate');
        var rate = kpis.resolve_rate || 0;
        rateEl.textContent = rate + '%';
        rateEl.className = 'report-kpi-value ' + (rate >= 80 ? 'green' : rate >= 50 ? 'amber' : 'red');

        // ── Timeline chart ────────────────────────────────────────────────
        destroyChart('chartTimeline');
        var tl = data.timeline || [];
        // Thin out labels for readability if > 14 days
        var tlLabels = tl.map(function(d, i) {
            if (tl.length <= 14) return d.date;
            return i % Math.ceil(tl.length / 14) === 0 ? d.date : '';
        });
        chartInstances['chartTimeline'] = new Chart(
            document.getElementById('chartTimeline').getContext('2d'), {
            type: 'line',
            data: {
                labels: tl.map(function(d){ return d.date; }),
                datasets: [{
                    label: 'Tickets Submitted',
                    data: tl.map(function(d){ return d.count; }),
                    borderColor: '#4f8ef7',
                    backgroundColor: 'rgba(79,142,247,0.12)',
                    borderWidth: 2,
                    pointRadius: tl.length <= 14 ? 4 : 2,
                    pointBackgroundColor: '#4f8ef7',
                    fill: true,
                    tension: 0.35,
                }]
            },
            options: {
                responsive: true, maintainAspectRatio: false,
                plugins: { legend: { display: false } },
                scales: {
                    x: {
                        ticks: {
                            color: '#8892a4', font: { size: 10 },
                            maxTicksLimit: 10,
                            maxRotation: 45,
                        },
                        grid: { color: 'rgba(255,255,255,0.04)' }
                    },
                    y: {
                        ticks: { color: '#8892a4', font: { size: 10 }, stepSize: 1, precision: 0 },
                        grid: { color: 'rgba(255,255,255,0.06)' },
                        beginAtZero: true,
                    }
                }
            }
        });

        // ── Status donut chart ────────────────────────────────────────────
        destroyChart('chartStatus');
        var st = data.status_breakdown || {};
        var stLabels = Object.keys(st);
        var stValues = stLabels.map(function(k){ return st[k]; });
        var stColors = { 'New': '#3b82f6', 'In Progress': '#f59e0b', 'Resolved': '#22c55e', 'Closed': '#94a3b8' };
        chartInstances['chartStatus'] = new Chart(
            document.getElementById('chartStatus').getContext('2d'), {
            type: 'doughnut',
            data: {
                labels: stLabels,
                datasets: [{
                    data: stValues,
                    backgroundColor: stLabels.map(function(l){ return stColors[l] || '#64748b'; }),
                    borderWidth: 0,
                    hoverOffset: 8,
                }]
            },
            options: {
                responsive: true, maintainAspectRatio: false,
                cutout: '62%',
                plugins: {
                    legend: {
                        position: 'bottom',
                        labels: { color: '#8892a4', font: { size: 11 }, padding: 16 }
                    }
                }
            }
        });

        // ── Priority bar chart ────────────────────────────────────────────
        destroyChart('chartPriority');
        var pr = data.priority_breakdown || {};
        var prLabels = ['Low', 'Medium', 'High', 'Urgent'];
        var prValues = prLabels.map(function(k){ return pr[k] || 0; });
        var prColors = ['#22c55e', '#3b82f6', '#f59e0b', '#ef4444'];
        chartInstances['chartPriority'] = new Chart(
            document.getElementById('chartPriority').getContext('2d'), {
            type: 'bar',
            data: {
                labels: prLabels,
                datasets: [{
                    label: 'Tickets',
                    data: prValues,
                    backgroundColor: prColors,
                    borderRadius: 8,
                    borderSkipped: false,
                }]
            },
            options: {
                responsive: true, maintainAspectRatio: false,
                plugins: { legend: { display: false } },
                scales: {
                    x: { ticks: { color: '#8892a4', font: { size: 11 } }, grid: { display: false } },
                    y: {
                        ticks: { color: '#8892a4', font: { size: 10 }, stepSize: 1, precision: 0 },
                        grid: { color: 'rgba(255,255,255,0.06)' },
                        beginAtZero: true,
                    }
                }
            }
        });

        // ── Resolve rate trend line chart ─────────────────────────────────
        destroyChart('chartResolveTrend');
        var rt = data.resolve_trend || [];
        chartInstances['chartResolveTrend'] = new Chart(
            document.getElementById('chartResolveTrend').getContext('2d'), {
            type: 'line',
            data: {
                labels: rt.map(function(d){ return d.week; }),
                datasets: [{
                    label: 'Resolve Rate %',
                    data: rt.map(function(d){ return d.rate; }),
                    borderColor: '#22c55e',
                    backgroundColor: 'rgba(34,197,94,0.1)',
                    borderWidth: 2.5,
                    pointRadius: 5,
                    pointBackgroundColor: '#22c55e',
                    fill: true,
                    tension: 0.3,
                }]
            },
            options: {
                responsive: true, maintainAspectRatio: false,
                plugins: {
                    legend: { display: false },
                    tooltip: {
                        callbacks: {
                            label: function(ctx){ return ctx.parsed.y + '%'; }
                        }
                    }
                },
                scales: {
                    x: { ticks: { color: '#8892a4', font: { size: 11 } }, grid: { color: 'rgba(255,255,255,0.04)' } },
                    y: {
                        ticks: { color: '#8892a4', font: { size: 10 }, callback: function(v){ return v + '%'; } },
                        grid: { color: 'rgba(255,255,255,0.06)' },
                        beginAtZero: true,
                        max: 100,
                    }
                }
            }
        });
    }

});
//
